package installer

import (
	"fmt"
	"path/filepath"
)

const (
	trackerGOGC       = "300"
	trackerGOMEMLIMIT = "700MiB"
	processorGOGC     = "100"
)

func renderSecrets(profile *InstallProfile) []byte {
	lines := []string{
		"REDIS_URL=redis://localhost:6379",
		"ESPX_TELEMETRY_ENABLED=" + boolString(profile.TelemetryEnabled),
		"TRACKER_INGRESS_SCHEMA=" + string(profile.IngressSchema),
		"GOGC=" + trackerGOGC,
		"GOMEMLIMIT=" + trackerGOMEMLIMIT,
	}
	return []byte(joinLines(lines))
}

func renderComposeEnv(profile *InstallProfile) []byte {
	lines := []string{
		"# Generated by espx-install apply — do not edit by hand",
		"TRACKER_INGRESS_SCHEMA=" + string(profile.IngressSchema),
		"GOGC=" + trackerGOGC,
		"GOMEMLIMIT=" + trackerGOMEMLIMIT,
		"PROCESSOR_GOGC=" + processorGOGC,
	}
	return []byte(joinLines(lines))
}

func composeEnvPath() string {
	if root := installRoot(); root != "" {
		return filepath.Join(root, "install.compose.env")
	}
	return filepath.Join(repoRoot(), "install.compose.env")
}

func joinLines(lines []string) string {
	out := ""
	for i, line := range lines {
		if i > 0 {
			out += "\n"
		}
		out += line
	}
	return out + "\n"
}

func applyServiceBinaries(profile *InstallProfile, dryRun bool) error {
	deploys := []struct {
		name   string
		spec   ServiceDeploy
		target string
	}{
		{"tracker", profile.Tracker, "/usr/local/bin/tracker"},
		{"processor", profile.Processor, "/usr/local/bin/processor"},
	}
	for _, d := range deploys {
		if d.spec.Binary == "" {
			continue
		}
		if dryRun {
			fmt.Printf("[Dry-Run] Would deploy %s from %s (health=%s)\n", d.name, d.spec.Binary, d.spec.HealthURL)
			continue
		}
		deploy := &BinaryDeploy{
			Service:    d.name,
			SourcePath: d.spec.Binary,
			TargetPath: d.target,
			HealthURL:  d.spec.HealthURL,
			Version:    d.spec.Version,
		}
		if err := deploy.DeployBinary(); err != nil {
			return fmt.Errorf("%s deploy: %w", d.name, err)
		}
		fmt.Printf("Deployed %s from %s\n", d.name, d.spec.Binary)
	}
	return nil
}

func rollbackUnitPath(service string) string {
	if root := installRoot(); root != "" {
		return filepath.Join(root, "etc/systemd/system", "espx-rollback@"+service+".service")
	}
	return filepath.Join("/etc/systemd/system", "espx-rollback@"+service+".service")
}

func renderRollbackUnit(service string) []byte {
	return []byte(fmt.Sprintf(`[Unit]
Description=eSPX rollback %s after crash loop
After=network.target

[Service]
Type=oneshot
ExecStart=/usr/local/bin/espx-install rollback %s
`, service, service))
}

func writeRollbackUnits(profile *InstallProfile, dryRun bool) error {
	if profile.Type != ProfileSingleVPS {
		return nil
	}
	for _, svc := range []string{"tracker", "processor"} {
		content := renderRollbackUnit(svc)
		path := rollbackUnitPath(svc)
		if dryRun {
			fmt.Printf("[Dry-Run] Would render %s\n", path)
			continue
		}
		if err := writeFile(path, content, 0644); err != nil {
			return err
		}
	}
	return nil
}
